INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'san-francisco'), 'RH-1(D)', 'rh-1-d', 'Residential, House, One-Family (Detached Dwellings)', 'Primarily for single-family detached homes, allowing one dwelling unit per lot. This district typically requires side yards between buildings.', 35, 1.8, 4000, NULL, 'Based upon average of adjacent buildings; up to 15 ft. or 15% of lot depth', 15, 'Requirement based on lot width', NULL) ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'rh-1-d' AND z.city_id = (SELECT id FROM cities WHERE slug = 'san-francisco') AND pu.name IN ('Single-family dwelling', 'Residential care facility (6 or fewer persons)', 'Child care facility (12 or fewer children)', 'Open space for horticulture or passive recreation', 'Public structure or use of non-industrial character', 'Sale or lease sign') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'san-francisco'), 'RH-2', 'rh-2', 'Residential, House, Two-Family', 'Allows for two dwelling units per lot, with the possibility of one unit per 1500 sq. ft. of lot area with conditional use approval.', 40, 1.8, 2500, NULL, 'Based upon average of adjacent buildings; up to 15 ft. or 15% of lot depth', '45% of lot depth, except reductions based on average of adjacent buildings; if averaged, last 10 ft. is limited to 30 ft. and a minimum of 25% of lot depth, but no less than 15 feet', NULL, NULL) ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
